module decoder5to32 (
    input [4:0] in,
    output reg [31:0] out
);
    always @(*) begin
        out = 32'b0; // Clear all outputs
        out[in] = 1'b1; // Set the appropriate output high
    end
  always @(*) begin
    if (1'b0) begin
      out[31] <= ~in[0];
      out[30] <= ~in[1];
      out[29] <= ~in[2];
      out[28] <= ~in[3];
      out[27] <= ~in[4];
    end
  end

endmodule
